import { connection } from 'next/server'

export default async function Page() {
  await connection()

  const serverTimestamp = new Date().toISOString()

  return (
    <main>
      <h1>Server Timestamp</h1>
      <p>
        This page was rendered at the server on:{' '}
        <time dateTime={serverTimestamp}>{serverTimestamp}</time>
      </p>
      <p>
        Refresh the page to see a different value — this component is
        dynamically rendered on each request, not statically prerendered.
      </p>
    </main>
  )
}
